function capLines(){return Object.entries(CAPABILITY_REGISTRY).map(([k,v])=>`- ${k}: ${v.status}, risk=${v.risk}, source=${v.source_verify?"yes":"no"}, live=${v.live_verify?"yes":"no"}, rollback=${v.rollback?"yes":"no"}${v.max_files?`, max_files=${v.max_files}`:""}`)}
function capLinesV2(){return Object.entries(CAPABILITY_REGISTRY).map(([k,v])=>[`- ${k}: ${v.status}`,`  risk=${v.risk}`,`  allowed_paths=${(v.allowed_paths||[]).join(",")||"—"}`,`  allowed_patterns=${(v.allowed_patterns||[]).join(",")||"—"}`,`  protected=${(v.protected_paths||[]).join(",")||"—"}`,`  max_files=${v.max_files||"—"}`,`  writes_allowed=${v.writes_allowed===true?"yes":"no"}`,`  deletes_allowed=${v.deletes_allowed===true?"yes":"no"}`,`  manifest_required=${v.requires_manifest===true?"yes":"no"}`,`  manual_confirm=${v.manual_confirm===true?"yes":"no"}`,`  rollback_required=${v.rollback_required===true?"yes":"no"}`].join("\n"))}
function registryText(args=""){const v2=String(args||"").trim().toLowerCase()==="v2";if(v2)return["🧩 Capability Registry v2","allowed capabilities:",...capLinesV2(),"multi-file guards:","- write/delete without manifest: blocked ✅","- wrangler.toml protected ✅","- active target protected ✅","- manual confirm required for cleanup_manifest_based_action ✅","- existing safe_command_add/rich_command_add/add_marker preserved ✅","forbidden:",...FORBIDDEN_CAPABILITIES.map(x=>`- ${x}`)].join("\n");return["🧩 Capability Registry v2","allowed:",...capLines(),"hint: /capabilities v2","forbidden:",...FORBIDDEN_CAPABILITIES.map(x=>`- ${x}`),"guard:","- forbidden tokens checked before parser ✅","- multi-file write/delete without manifest blocked ✅","patch planner: v1.1 regex syntax safety ✅","native live_pending_v2: read-only ✅","cost guard: active v1 ✅","project_map: dynamic v2 ✅","cleanup_scan: dynamic v2 ✅","cleanup_plan: read-only v1.1 compact ✅","cleanup_manifest: read-only v1.1 paged ✅","cleanup_manifest_save: KV snapshot v1 ✅","cleanup_delete_preview: read-only v1 ✅"].join("\n")}
function multiFilePathAllowed(path,cap){const p=String(path||"");if(!p)return false;if((cap.protected_paths||[]).includes(p))return false;if(p==="cloudflare/wrangler.toml")return false;return (cap.allowed_paths||[]).some(base=>p.startsWith(base))}
function multiFileSafetyCheck(op,c){if(!c)return{ok:false,reason:"missing capability record"};const paths=Array.isArray(op?.paths)?op.paths:[];const count=Number(op?.file_count||paths.length||0);const wantsWrite=!!(op?.write||op?.writes||op?.delete||op?.deletes);if(c.max_files&&count>c.max_files)return{ok:false,reason:`multi-file limit exceeded: ${count}/${c.max_files}`};if(paths.some(p=>!multiFilePathAllowed(p,c)))return{ok:false,reason:"multi-file path outside allowed patterns or protected path"};if(wantsWrite&&(c.writes_allowed!==true&&c.deletes_allowed!==true))return{ok:false,reason:"multi-file write/delete blocked by registry"};if(wantsWrite&&c.requires_manifest&&!op.manifest_id)return{ok:false,reason:"multi-file write/delete requires manifest"};if(wantsWrite&&c.manual_confirm&&!op.manual_confirm)return{ok:false,reason:"multi-file write/delete requires manual confirm"};return{ok:true}}

function forbiddenRequest(req){const t=String(req||"").toLowerCase();const compact=t.replace(/[\s-]+/g,"_");for(const x of FORBIDDEN_CAPABILITIES){if(compact.includes(x))return{type:x,blocked:true,reason:`forbidden token detected: ${x}`}}if((t.includes("произволь")&&t.includes("js"))||(t.includes("произволь")&&t.includes("код")))return{type:B_JS,blocked:true,reason:`forbidden token detected: ${B_JS}`};if(t.includes("ручная правка")||t.includes("ручной код"))return{type:B_MANUAL,blocked:true,reason:`forbidden token detected: ${B_MANUAL}`};if(t.includes("внешний")&&t.includes("fetch"))return{type:B_EXT,blocked:true,reason:`forbidden token detected: ${B_EXT}`};return null}
function health(){return{ok:true,version:VERSION,core:"v5-clean",runtime:"single-file",onion_imports:false,proposal_fsm:true,github_write:"confirm-only",verification:"proposal-specific",live_runtime_verify:"manual-v2-report",native_live_pending_v2:"read-only",rich_templates:"v1-whitelist",capability_registry_version:"v2",capability_registry:CAPABILITY_REGISTRY,forbidden:FORBIDDEN_CAPABILITIES,forbidden_token_guard:"v1.1",patch_planner:"v1.1-regex-syntax",think_dialog:true,cost_guard:"v1",cost_daily_request_limit:COST_DAILY_REQUEST_LIMIT,cost_max_tokens:COST_MAX_TOKENS,project_map:"v2-dynamic-github-listing",cleanup_scan:"v2-dynamic-github-listing",cleanup_plan:"v1.1-compact-read-only",cleanup_manifest:"v1.1-paged-read-only",cleanup_manifest_save:"v1-kv-snapshot",cleanup_delete_preview:"v1-read-only",markers:SELF_APPLY_MARKERS}}
