async function listRepoDir(c,path=""){const p=clean(path),part=p?`/${pathUrl(p)}`:"";const headers={accept:"application/vnd.github+json","user-agent":"MiniSkynet-v520"};if(c.gh)headers.authorization=`Bearer ${c.gh}`;const r=await fetch(`https://api.github.com/repos/${c.repo}/contents${part}?ref=${encodeURIComponent(c.branch)}`,{headers});const d=await r.json().catch(()=>({}));if(!r.ok)throw new Error(`GitHub listing ${p||"/"} ${r.status}: ${d.message||"request failed"}`);if(!Array.isArray(d))throw new Error(`GitHub listing ${p||"/"} is not a directory`);return d.map(x=>({path:x.path||"",type:x.type||"",size:x.size||0,sha:x.sha||""}))}
async function listRepoTree(c){const roots=["","cloudflare","cloudflare/src",".github",".github/workflows"],seen=new Set(),all=[];for(const root of roots){try{for(const e of await listRepoDir(c,root)){if(!seen.has(e.path)){seen.add(e.path);all.push(e)}}}catch(e){if(root==="")throw e;all.push({path:root,type:"error",size:0,sha:"",error:String(e.message||e)})}}return all.sort((a,b)=>a.path.localeCompare(b.path))}
function projectFileClass(item,activePath,wranglerMain){const p=item.path||"";if(item.type==="error")return{kind:"unknown",risk:"medium",reason:"listing error"};if(p==="cloudflare/wrangler.toml"||p===activePath)return{kind:"protected",risk:"critical",reason:p===activePath?"active runtime target":"worker config"};if(p===".github"||p.startsWith(".github/")||p==="package.json"||p==="package-lock.json"||p.endsWith("wrangler.toml"))return{kind:"config",risk:"high",reason:"configuration/CI"};if(p===wranglerMain)return{kind:"protected",risk:"critical",reason:"wrangler main target"};if(p.startsWith("cloudflare/src/")&&p.endsWith(".js"))return{kind:"report-only",risk:"medium",reason:"non-active worker/runtime candidate"};if(p.endsWith(".md")||p.endsWith(".txt")||p.endsWith(".json")||p.endsWith(".yml")||p.endsWith(".yaml"))return{kind:"report-only",risk:"low",reason:"metadata/report/config-like"};if(item.type==="dir")return{kind:"report-only",risk:"low",reason:"directory"};return{kind:"unknown",risk:"medium",reason:"unclassified"}}
function pushLimited(lines,title,items,limit=14){lines.push(`${title}: ${items.length}`);if(!items.length){lines.push("- none");return}for(const x of items.slice(0,limit))lines.push(`- ${x.path} risk=${x.risk} ${x.reason||""}`);if(items.length>limit)lines.push(`- ... +${items.length-limit} more`)}
async function projectMapV2(env,c){let active,tree;try{active=await activeTarget(c);tree=await listRepoTree(c)}catch(e){return["🗺️ Project Map v2","mode: read-only GitHub directory listing","state: ERROR ❌",`error: ${String(e.message||e)}`,"GitHub write: none ✅","wrangler.toml changes: none ✅"].join("\n")}const groups={protected:[],config:[],runtime:[],report:[],unknown:[]};for(const item of tree){const cls=projectFileClass(item,active.file.path,active.main),row={...item,...cls};if(cls.kind==="protected")groups.protected.push(row);else if(cls.kind==="config")groups.config.push(row);else if(cls.kind==="runtime")groups.runtime.push(row);else if(cls.kind==="report-only")groups.report.push(row);else groups.unknown.push(row)}const lines=["🗺️ Project Map v2","mode: read-only GitHub directory listing","GitHub write: none ✅","delete files: none ✅","wrangler.toml changes: none ✅",`repo: ${c.repo}`,`branch: ${c.branch}`,`wrangler main: ${active.main}`,`active target: ${active.file.path}`,`active sha: ${active.file.sha.slice(0,12)}`,`files/dirs seen: ${tree.length}`];pushLimited(lines,"protected files",groups.protected);pushLimited(lines,"config files",groups.config);pushLimited(lines,"runtime files",groups.runtime);pushLimited(lines,"report-only files",groups.report);pushLimited(lines,"unknown files",groups.unknown);return lines.join("\n")}

function cleanupCandidateClass(item,activePath){const p=item.path||"";if(item.type!=="file")return null;if(p===activePath)return{kind:"protected",risk:"critical",reason:"active runtime target"};if(p==="cloudflare/wrangler.toml")return{kind:"protected",risk:"critical",reason:"worker config protected"};if(p.startsWith("cloudflare/src/")&&/^index-v\d+\.js$/.test(p.split("/").pop()))return{kind:"candidate",risk:"medium",reason:"versioned non-active worker file"};if(p.startsWith("cloudflare/src/")&&/^worker-.*\.js$/i.test(p.split("/").pop()))return{kind:"candidate",risk:"medium",reason:"legacy worker wrapper candidate"};if(p.startsWith("cloudflare/src/")&&p.endsWith(".js")&&/(legacy|old|backup|wrapper|archive|copy)/i.test(p))return{kind:"candidate",risk:"medium",reason:"old/backup/wrapper JS candidate"};return null}
function pushCleanupList(lines,title,items,limit=30){lines.push(`${title}: ${items.length}`);if(!items.length){lines.push("- none");return}for(const x of items.slice(0,limit))lines.push(`- ${x.path} risk=${x.risk} reason=${x.reason}`);if(items.length>limit)lines.push(`- ... +${items.length-limit} more`)}
async function cleanupScanV2(env,c){let active,tree;try{active=await activeTarget(c);tree=await listRepoTree(c)}catch(e){return["🧹 Cleanup Scan v2","mode: read-only GitHub directory listing","state: ERROR ❌",`error: ${String(e.message||e)}`,"GitHub write: none ✅","delete files: none ✅","wrangler.toml changes: none ✅"].join("\n")}const candidates=[],protectedFiles=[];for(const item of tree){const cls=cleanupCandidateClass(item,active.file.path);if(!cls)continue;const row={...item,...cls};if(cls.kind==="protected")protectedFiles.push(row);else if(cls.kind==="candidate")candidates.push(row)}const lines=["🧹 Cleanup Scan v2","mode: read-only GitHub directory listing","GitHub write: none ✅","delete files: none ✅","wrangler.toml changes: none ✅","auto cleanup: disabled ✅",`repo: ${c.repo}`,`branch: ${c.branch}`,`wrangler main: ${active.main}`,`active target: ${active.file.path}`,`active sha: ${active.file.sha.slice(0,12)}`,`files/dirs seen: ${tree.length}`];pushCleanupList(lines,"protected files",protectedFiles,10);pushCleanupList(lines,"legacy/non-active worker candidates",candidates,35);lines.push("next manual step: review candidates only; deletion is not implemented in this command");return lines.join("\n")}

function cleanupPlanSort(a,b){const pa=a.path||"",pb=b.path||"";const ai=/index-v\d+\.js$/.test(pa)?0:/worker-.*\.js$/i.test(pa)?1:2;const bi=/index-v\d+\.js$/.test(pb)?0:/worker-.*\.js$/i.test(pb)?1:2;if(ai!==bi)return ai-bi;return pa.localeCompare(pb)}
function cleanupPlanGroup(items){const indexFiles=[],workerFiles=[],otherFiles=[];for(const x of items){const name=(x.path||"").split("/").pop();if(/^index-v\d+\.js$/.test(name))indexFiles.push(x);else if(/^worker-.*\.js$/i.test(name))workerFiles.push(x);else otherFiles.push(x)}return{indexFiles,workerFiles,otherFiles}}
function pushPlanGroup(lines,title,items,reason,limit=10){lines.push(`${title}: ${items.length}`);if(!items.length){lines.push("- none");return}for(const x of items.slice(0,limit))lines.push(`- ${x.path} risk=${x.risk||"medium"} reason=${reason||x.reason||"legacy candidate"}`);if(items.length>limit)lines.push(`- ... +${items.length-limit} more`)}
async function cleanupPlanV1(env,c){let active,tree;try{active=await activeTarget(c);tree=await listRepoTree(c)}catch(e){return["🧭 Cleanup Plan v1","mode: read-only GitHub directory listing","state: ERROR ❌",`error: ${String(e.message||e)}`,"GitHub write: none ✅","delete files: none ✅","wrangler.toml changes: none ✅"].join("\n")}const candidates=[],protectedFiles=[];for(const item of tree){const cls=cleanupCandidateClass(item,active.file.path);if(!cls)continue;const row={...item,...cls};if(cls.kind==="protected")protectedFiles.push(row);else if(cls.kind==="candidate")candidates.push(row)}candidates.sort(cleanupPlanSort);const g=cleanupPlanGroup(candidates),deleteOrder=[...g.indexFiles,...g.workerFiles,...g.otherFiles];const lines=["🧭 Cleanup Plan v1","mode: read-only GitHub directory listing","GitHub write: none ✅","delete files: none ✅","wrangler.toml changes: none ✅","auto cleanup: disabled ✅",`repo: ${c.repo}`,`branch: ${c.branch}`,`wrangler main: ${active.main}`,`active target: ${active.file.path}`,`active sha: ${active.file.sha.slice(0,12)}`,`files/dirs seen: ${tree.length}`,`estimated files count: ${deleteOrder.length}`,"full candidate list: /cleanup_scan","compact output: first 10 per group ✅","protected files:"];for(const p of protectedFiles.slice(0,10))lines.push(`- ${p.path} risk=${p.risk} reason=${p.reason}`);if(!protectedFiles.length)lines.push("- none");lines.push("delete order: 1) index-v*.js snapshots, 2) worker-*.js wrappers, 3) other old/backup JS candidates");pushPlanGroup(lines,"group 1 index-v*.js",g.indexFiles,"versioned non-active worker snapshot");pushPlanGroup(lines,"group 2 worker-*.js",g.workerFiles,"legacy worker wrapper");pushPlanGroup(lines,"group 3 other old/backup JS",g.otherFiles,"old/backup/wrapper JS candidate");lines.push("risk: medium overall — files are non-active candidates, but deletion must be reviewed before any write");lines.push("rollback note: if deleted later, restore by GitHub commit revert or by re-uploading files from the last known commit; this command does not delete anything");lines.push("next manual step: review plan only; deletion capability is not implemented here");return lines.join("\n")}

function manifestReasonCode(reason){if((reason||"").includes("versioned"))return"index-snapshot";if((reason||"").includes("wrapper"))return"worker-wrapper";return"old-js"}
function manifestRows(items){return items.map(x=>`- ${x.path} sha=${(x.sha||"").slice(0,10)} risk=${x.risk||"medium"} reason=${manifestReasonCode(x.reason)}`)}
function manifestPageInfo(total,page,pageSize){const pages=Math.max(1,Math.ceil(total/pageSize));const safePage=Math.min(Math.max(1,page||1),pages);const start=(safePage-1)*pageSize,end=Math.min(total,start+pageSize);return{pages,safePage,start,end}}
async function cleanupManifestV1(env,c,args=""){let active,tree,wrangler;try{active=await activeTarget(c);tree=await listRepoTree(c);wrangler=await readFile(c,"cloudflare/wrangler.toml")}catch(e){return["📜 Cleanup Manifest v1.1","mode: read-only GitHub directory listing","state: ERROR ❌",`error: ${String(e.message||e)}`,"GitHub write: none ✅","delete files: none ✅","wrangler.toml changes: none ✅"].join("\n")}const candidates=[],protectedFiles=[];for(const item of tree){const cls=cleanupCandidateClass(item,active.file.path);if(!cls)continue;const row={...item,...cls};if(cls.kind==="protected")protectedFiles.push(row);else if(cls.kind==="candidate")candidates.push(row)}candidates.sort(cleanupPlanSort);const pageSize=20,requestedPage=parseInt((args||"").trim(),10),info=manifestPageInfo(candidates.length,requestedPage,pageSize);const isPage=Number.isFinite(requestedPage)&&requestedPage>0;const lines=["📜 Cleanup Manifest v1.1","mode: read-only GitHub directory listing","GitHub write: none ✅","delete files: none ✅","wrangler.toml changes: none ✅",`repo: ${c.repo}`,`branch: ${c.branch}`,`rollback source active_sha: ${active.file.sha.slice(0,12)}`,`rollback source note: restore by GitHub commit revert or re-upload from this sha/commit before deletion`,`wrangler main: ${active.main}`,`wrangler.toml sha: ${wrangler.sha.slice(0,12)}`,`active target: ${active.file.path}`,`active target sha: ${active.file.sha.slice(0,12)}`,`estimated legacy candidates: ${candidates.length}`,`manifest pages: ${info.pages} (${pageSize} per page)`];if(!isPage){lines.push("wrangler.toml protected content preview:");lines.push(clip(wrangler.content,360));lines.push("protected files:");for(const p of protectedFiles.slice(0,10))lines.push(`- ${p.path} sha=${(p.sha||"").slice(0,10)} risk=${p.risk} reason=${p.reason}`);if(!protectedFiles.length)lines.push("- none");lines.push("manifest view: use /cleanup_manifest 1, /cleanup_manifest 2, /cleanup_manifest 3 for full path/sha pages");lines.push("final note: summary only; no delete capability here");return lines.join("\n")}lines.push(`manifest page: ${info.safePage}/${info.pages}`,`items: ${info.start+1}-${info.end} of ${candidates.length}`,"manifest candidates path/sha/risk/reason:");for(const row of manifestRows(candidates.slice(info.start,info.end)))lines.push(row);lines.push(info.safePage<info.pages?`next page: /cleanup_manifest ${info.safePage+1}`:"next page: none");lines.push("final note: manifest page only; no delete capability here");return lines.join("\n")}

function cleanupManifestBuildRows(tree,activePath){const candidates=[],protectedFiles=[];for(const item of tree){const cls=cleanupCandidateClass(item,activePath);if(!cls)continue;const row={...item,...cls};if(cls.kind==="protected")protectedFiles.push(row);else if(cls.kind==="candidate")candidates.push(row)}candidates.sort(cleanupPlanSort);return{candidates,protectedFiles}}
function cleanupManifestRecord(c,active,wrangler,rows){return{manifest_id:uid("cm"),created_at:now(),repo:c.repo,branch:c.branch,active_target:active.file.path,active_sha:active.file.sha,wrangler_path:"cloudflare/wrangler.toml",wrangler_sha:wrangler.sha,wrangler_main:active.main,count:rows.candidates.length,protected:rows.protectedFiles.map(x=>({path:x.path,sha:x.sha,risk:x.risk,reason:x.reason})),candidates:rows.candidates.map(x=>({path:x.path,sha:x.sha,risk:x.risk||"medium",reason:manifestReasonCode(x.reason)}))}}
async function buildCleanupManifestRecord(env,c){const active=await activeTarget(c),tree=await listRepoTree(c),wrangler=await readFile(c,"cloudflare/wrangler.toml"),rows=cleanupManifestBuildRows(tree,active.file.path);return cleanupManifestRecord(c,active,wrangler,rows)}
async function cleanupManifestSaveV1(env,c){try{const m=await buildCleanupManifestRecord(env,c);await kvPut(env,`cleanup_manifest:${m.manifest_id}`,m);await kvPut(env,"cleanup_manifest:last",{manifest_id:m.manifest_id,created_at:m.created_at,active_sha:m.active_sha,wrangler_sha:m.wrangler_sha,count:m.count});return["💾 Cleanup Manifest Save v1","mode: GitHub listing read + KV save","GitHub write: none ✅","delete files: none ✅","wrangler.toml changes: none ✅","KV write: manifest snapshot ✅",`manifest_id: ${m.manifest_id}`,`created_at: ${m.created_at}`,`active_target: ${m.active_target}`,`active_sha: ${m.active_sha.slice(0,12)}`,`wrangler_sha: ${m.wrangler_sha.slice(0,12)}`,`candidates_count: ${m.count}`,`saved_key: cleanup_manifest:${m.manifest_id}`,`next: /cleanup_manifest_saved ${m.manifest_id}`].join("\n")}catch(e){return["💾 Cleanup Manifest Save v1","state: ERROR ❌",`error: ${String(e.message||e)}`,"GitHub write: none ✅","delete files: none ✅","wrangler.toml changes: none ✅"].join("\n")}}
function savedManifestPage(m,page){const pageSize=20,info=manifestPageInfo(m.candidates.length,page,pageSize),lines=[`manifest page: ${info.safePage}/${info.pages}`,`items: ${info.start+1}-${info.end} of ${m.candidates.length}`,"candidates path/sha/risk/reason:"];for(const x of m.candidates.slice(info.start,info.end))lines.push(`- ${x.path} sha=${String(x.sha||"").slice(0,10)} risk=${x.risk||"medium"} reason=${x.reason}`);lines.push(info.safePage<info.pages?`next page: /cleanup_manifest_saved ${m.manifest_id} ${info.safePage+1}`:"next page: none");return lines}
async function cleanupManifestSavedV1(env,args=""){const parts=String(args||"").trim().split(/\s+/).filter(Boolean);let id=parts[0]||"",page=parseInt(parts[1]||"",10);if(!id){const last=await kvGet(env,"cleanup_manifest:last",null);id=last?.manifest_id||""}if(!id)return"Формат: /cleanup_manifest_saved manifest_id";const m=await kvGet(env,`cleanup_manifest:${id}`,null);if(!m)return`Не нашёл cleanup manifest: ${id}`;const pages=Math.max(1,Math.ceil((m.candidates||[]).length/20));const lines=["📦 Cleanup Manifest Saved v1","mode: KV snapshot read-only","GitHub write: none ✅","delete files: none ✅","wrangler.toml changes: none ✅",`manifest_id: ${m.manifest_id}`,`created_at: ${m.created_at}`,`repo: ${m.repo}`,`branch: ${m.branch}`,`active_target: ${m.active_target}`,`active_sha: ${String(m.active_sha||"").slice(0,12)}`,`wrangler_sha: ${String(m.wrangler_sha||"").slice(0,12)}`,`estimated candidates: ${(m.candidates||[]).length}`,`manifest pages: ${pages} (20 per page)`];if(Number.isFinite(page)&&page>0){lines.push(...savedManifestPage(m,page));return lines.join("\n")}lines.push("protected files:");for(const p of (m.protected||[]).slice(0,10))lines.push(`- ${p.path} sha=${String(p.sha||"").slice(0,10)} risk=${p.risk} reason=${p.reason}`);if(!(m.protected||[]).length)lines.push("- none");lines.push(`view candidates: /cleanup_manifest_saved ${m.manifest_id} 1`);lines.push("final note: saved snapshot only; no delete capability here");return lines.join("\n")}

function cleanupDeleteGroup(path){const name=String(path||"").split("/").pop();if(/^index-v\d+\.js$/.test(name))return"index-v*.js snapshots";if(/^worker-.*\.js$/i.test(name))return"worker-*.js wrappers";return"other old/backup JS"}
function cleanupDeleteOrderRows(items){return [...items].sort((a,b)=>{const ga=cleanupDeleteGroup(a.path),gb=cleanupDeleteGroup(b.path),ra=ga.startsWith("index")?0:ga.startsWith("worker")?1:2,rb=gb.startsWith("index")?0:gb.startsWith("worker")?1:2;if(ra!==rb)return ra-rb;return String(a.path).localeCompare(String(b.path))})}
function pushPreviewSample(lines,title,items,limit=12){lines.push(`${title}: ${items.length}`);if(!items.length){lines.push("- none");return}for(const x of items.slice(0,limit))lines.push(`- ${x.path} manifest=${String(x.manifest_sha||x.sha||"").slice(0,10)} current=${String(x.current_sha||"").slice(0,10)||"missing"} reason=${x.reason||"—"}`);if(items.length>limit)lines.push(`- ... +${items.length-limit} more`)}
async function cleanupDeletePreviewV1(env,c,args=""){const id=String(args||"").trim().split(/\s+/).filter(Boolean)[0]||"";if(!id)return"Формат: /cleanup_delete_preview manifest_id";let m,active,tree,wrangler;try{m=await kvGet(env,`cleanup_manifest:${id}`,null);if(!m)return`Не нашёл cleanup manifest: ${id}`;active=await activeTarget(c);tree=await listRepoTree(c);wrangler=await readFile(c,"cloudflare/wrangler.toml")}catch(e){return["🧯 Cleanup Delete Preview v1","state: ERROR ❌",`error: ${String(e.message||e)}`,"GitHub write: none ✅","delete files: none ✅","wrangler.toml changes: none ✅"].join("\n")}const lines=["🧯 Cleanup Delete Preview v1","mode: saved manifest + live GitHub sha check","GitHub write: none ✅","delete files: none ✅","wrangler.toml changes: none ✅",`manifest_id: ${m.manifest_id}`,`manifest_created_at: ${m.created_at}`,`repo: ${m.repo}`,`branch: ${m.branch}`,`manifest active_sha: ${String(m.active_sha||"").slice(0,12)}`,`current active_sha: ${String(active.file.sha||"").slice(0,12)}`,`manifest wrangler_sha: ${String(m.wrangler_sha||"").slice(0,12)}`,`current wrangler_sha: ${String(wrangler.sha||"").slice(0,12)}`];if(String(m.active_sha||"")!==String(active.file.sha||"")){lines.push("state: BLOCKED ⛔","reason: active_sha changed after manifest save","risk: high","delete order: blocked","matched/stale/missing: not evaluated","next: run /cleanup_manifest_save again, then preview the new manifest_id");return lines.join("\n")}const current=new Map(tree.filter(x=>x.type==="file").map(x=>[x.path,x]));const matched=[],stale=[],missing=[];for(const cand of (m.candidates||[])){const cur=current.get(cand.path);if(!cur)missing.push({...cand,manifest_sha:cand.sha,current_sha:"",reason:"missing from current repo"});else if(String(cur.sha)!==String(cand.sha))stale.push({...cand,manifest_sha:cand.sha,current_sha:cur.sha,reason:"sha differs"});else matched.push({...cand,manifest_sha:cand.sha,current_sha:cur.sha,reason:cand.reason})}const protectedFiles=[{path:active.file.path,sha:active.file.sha,risk:"critical",reason:"active runtime target"},{path:"cloudflare/wrangler.toml",sha:wrangler.sha,risk:"critical",reason:"worker config protected"}];const blocked=stale.length||missing.length;lines.push(`candidates_count: ${(m.candidates||[]).length}`,`matched: ${matched.length}`,`stale: ${stale.length}`,`missing: ${missing.length}`,`protected: ${protectedFiles.length}`,`risk: ${blocked?"high - stale/missing candidates present":"medium - matched non-active candidates only"}`,blocked?"state: REVIEW_BLOCKED ⚠️":"state: PREVIEW_OK ✅","delete order: 1) index-v*.js snapshots, 2) worker-*.js wrappers, 3) other old/backup JS","protected files:");for(const p of protectedFiles)lines.push(`- ${p.path} sha=${String(p.sha||"").slice(0,10)} risk=${p.risk} reason=${p.reason}`);pushPreviewSample(lines,"stale candidates",stale,8);pushPreviewSample(lines,"missing candidates",missing,8);const ordered=cleanupDeleteOrderRows(matched);pushPreviewSample(lines,"matched delete-order sample",ordered,14);lines.push("final note: preview only; no delete capability executed");return lines.join("\n")}

async function coreCheck(env,c){const tasks=await arr(env,"tasks"),mem=await arr(env,"memories"),props=await arr(env,"proposals"),goals=await getGoals(env),plan=await getPlan(env);let target="ERROR",main="—",sha="—",size="—";try{const a=await activeTarget(c);target=a.file.path;main=a.main;sha=a.file.sha.slice(0,12);size=a.file.size}catch(e){target="ERROR: "+String(e.message||e)}const last=props[props.length-1],pending=await pendingSource(props),livePending=await pendingLive(props);return["🧭 Core Check",`version: ${VERSION}`,`active_target: ${target}`,`wrangler main: ${main}`,`sha: ${sha}`,`size: ${size}`,`think/dialog: ${c.openrouter?"active ✅":"no key ⛔"}`,`github token: ${c.gh?"connected ✅":"missing ⛔"}`,"capability registry: active ✅","forbidden token guard: active ✅","patch planner: active v1.1 ✅","native live_pending_v2: active ✅","cost guard: active v1 ✅",`tasks: active=${tasks.filter(t=>t.status!=="done").length}, done=${tasks.filter(t=>t.status==="done").length}`,`memory: ${mem.length}`,`goals: ${goals.goals?.length||0}`,`plan: ${plan.steps?.[0]||"—"}`,`proposals: ${props.length}`,`last proposal: ${last?`${last.id} [${last.state}]`:"none"}`,`pending verify: ${pending?pending.id:"none"}`,`pending live: ${livePending?`${livePending.id} [${livePending.live_runtime_verify.status}]`:"none"}`,"next:",pending?`/post_apply_verify ${pending.id}`:livePending?"/live_pending_v2":"/system_scan"].join("\n")}
async function systemScan(env,c){const tasks=await arr(env,"tasks"),mem=await arr(env,"memories"),props=await arr(env,"proposals");let target="unknown",err="";try{const a=await activeTarget(c);target=`${a.file.path} sha=${a.file.sha.slice(0,12)}`}catch(e){target="ERROR";err=String(e.message||e)}const active=tasks.filter(t=>t.status!=="done").length,done=tasks.filter(t=>t.status==="done").length,pending=await pendingSource(props),livePending=await pendingLive(props),blocks=[];if(err)blocks.push(`active_target: ${err}`);if(!c.gh)blocks.push("GitHub key missing");if(!c.openrouter)blocks.push("OpenRouter key missing");if(pending)blocks.push(`pending source verify: ${pending.id}`);if(livePending)blocks.push(`pending live verify: ${livePending.id}`);return["🧪 System Scan",`active target: ${target}`,`keys: github=${c.gh?"ok":"missing"}, openrouter=${c.openrouter?"ok":"missing"}`,`tasks: active=${active}, done=${done}`,`memory: ${mem.length}`,`proposals: ${props.length}`,"capability registry:",...capLines(),"forbidden:",...FORBIDDEN_CAPABILITIES.map(x=>`- ${x}`),"guard:","- forbidden tokens checked before parser ✅","patch planner:","- diff preview before apply_confirm ✅","- syntax safety structural check v1.1 ✅","- regex literals ignored ✅","- stale/no-op blockers ✅","- risk after diff/syntax ✅","live runtime:","- native /live_pending_v2 read-only ✅","- manual PASS/FAIL only ✅","cost guard:","- runThink daily budget active ✅","project map:","- dynamic GitHub listing active ✅","cleanup scan:","- dynamic GitHub listing active ✅","cleanup plan:","- read-only legacy plan active ✅","cleanup manifest:","- read-only paged path/sha manifest active ✅","- KV snapshot save active ✅","cleanup delete preview:","- manifest sha validation active ✅","capability registry v2:","- multi-file safe actions guarded ✅","- write/delete without manifest blocked ✅","weak spots:","- self-apply: safe_command_add static v1","- rich command templates: whitelist v1","blockers:",...(blocks.length?blocks.map(x=>`- ${x}`):["- none"]),"next:",pending?`/post_apply_verify ${pending.id}`:livePending?"/live_pending_v2":"/core_next"].join("\n")}
async function coreNext(env,c){const tasks=(await arr(env,"tasks")).filter(t=>t.status!=="done"),plan=await getPlan(env),props=await arr(env,"proposals"),pending=await pendingSource(props),livePending=await pendingLive(props),blockers=[];if(!c.gh)blockers.push("GitHub key missing");if(!c.openrouter)blockers.push("OpenRouter key missing");if(pending)blockers.push(`pending source verify: ${pending.id}`);if(livePending)blockers.push(`pending live verify: ${livePending.id}`);let source="none",step="";if(pending){source="blocker";step=`Проверить применённый proposal ${pending.id}`}else if(livePending){source="blocker";step=`Проверить live runtime для ${livePending.id}`}else if(blockers.length){source="blockers";step="Сначала убрать blocker: "+blockers[0]}else if(tasks.length){source="tasks";step=tasks.slice().sort((a,b)=>(a.p||4)-(b.p||4)||String(a.created_at||"").localeCompare(String(b.created_at||"")))[0].text||"—"}else if(plan.steps&&plan.steps.length){source="plan";step=plan.steps[0]}else step="Нет доступных шагов.";return["⏭ Core Next",`source: ${source}`,`step: ${step}`,"blockers:",...(blockers.length?blockers.map(x=>`- ${x}`):["- none"]),"command:",pending?`/post_apply_verify ${pending.id}`:livePending?"/live_pending_v2":tasks.length?"/tasks":"/system_scan"].join("\n")}
async function renderRichCommand(env,c,template,data){template=String(template||"").toLowerCase();data=String(data||"").toLowerCase();if(!RICH_ALLOWED[template]?.has(data))return`⛔ Rich template blocked: ${template}/${data}`;const tasks=await arr(env,"tasks"),mem=await arr(env,"memories"),props=await arr(env,"proposals"),goals=await getGoals(env),plan=await getPlan(env),active=tasks.filter(t=>t.status!=="done"),done=tasks.filter(t=>t.status==="done"),last=props[props.length-1];if(template==="status")return[`📊 Rich status: ${data}`,`version: ${VERSION}`,`tasks: ${active.length}/${done.length}`,`memory: ${mem.length}`,`proposals: ${props.length}`,`guard: active ✅`,`patch planner: active v1.1 ✅`].join("\n");if(template==="list"){if(data==="tasks")return active.length?"📋 Rich list: tasks\n"+active.slice(0,10).map((x,i)=>`${i+1}. ${x.id}: ${x.text}`).join("\n"):"📋 Rich list: tasks\nnone";if(data==="goals")return"📋 Rich list: goals\n"+(goals.goals||[]).map((x,i)=>`${i+1}. ${x}`).join("\n");if(data==="memory")return mem.length?"📋 Rich list: memory\n"+mem.slice(-8).map(x=>`- [${x.score||0}] ${x.text}`).join("\n"):"📋 Rich list: memory\nnone";if(data==="proposals")return props.length?"📋 Rich list: proposals\n"+props.slice(-8).map(p=>`- ${p.id} [${p.state}] ${p.title||p.request}`).join("\n"):"📋 Rich list: proposals\nnone";return"📋 Rich list: plan\n"+(plan.steps||[]).map((x,i)=>`${i+1}. ${x}`).join("\n")}if(template==="report")return[`🧾 Rich report: ${data}`,`version: ${VERSION}`,"capability registry: v1.1 ✅","forbidden token guard: v1.1 ✅","patch planner: v1.1 ✅",`last proposal: ${last?`${last.id} [${last.state}]`:"none"}`].join("\n");const pending=await pendingSource(props),live=await pendingLive(props);return[`✅ Rich check: ${data}`,`source verify: ${pending?pending.id:"none"}`,`live verify: ${live?live.id:"none"}`].join("\n")}
