  if(command==="/cleanup_manifest_saved")return send(c,chatId,await cleanupManifestSavedV1(env,args));
  if(command==="/cleanup_delete_preview")return send(c,chatId,await cleanupDeletePreviewV1(env,c,args));
  if(command==="/rollback_last")return send(c,chatId,await rollbackLast(env,c));
  if(command==="/confirm_rollback")return send(c,chatId,await confirmRollback(env,c,args));
