  if(command==="/capabilities")return send(c,chatId,registryText(args));
  if(command==="/rich_templates")return send(c,chatId,["🧩 Rich command templates v1","syntax:","/propose rich_command_add /cmd template=status data=core","","allowed:","status: core, repo, tasks, memory, proposals, system","list: tasks, goals, memory, proposals, plan","report: core, work, self_apply","check: keys, blockers, active_target, pending, live","","forbidden: arbitrary JS, external fetch, wrangler.toml changes"].join("\n"));
  if(command==="/status"){const tasks=await arr(env,"tasks"),mem=await arr(env,"memories"),props=await arr(env,"proposals");return send(c,chatId,["📡 MiniSkynet Core status",`- version: ${VERSION}`,"- runtime: single-file flat core","- proposal FSM: active","- GitHub write: /apply_check + /apply_confirm","- capability registry: active v2","- multi-file safe actions: guarded ✅","- forbidden token guard: active v1.1","- patch planner: active v1.1","- cost guard: active v1","- project_map: dynamic v2","- cleanup_scan: dynamic v2","- cleanup_plan: read-only v1.1 compact","- cleanup_manifest: read-only v1.1 paged","- cleanup_manifest_save: KV snapshot v1","- cleanup_delete_preview: read-only v1","- verification: proposal-specific","- live runtime verify: manual v2 report","- rich templates: whitelist v1",`- think/dialog: ${c.openrouter?"active ✅":"no key ⛔"}`,`- tasks: active=${tasks.filter(t=>t.status!=="done").length}, done=${tasks.filter(t=>t.status==="done").length}`,`- memory: ${mem.length}`,`- proposals: ${props.length}`,`- model: ${c.model}`].join("\n"))}
  if(command==="/health_check"||command==="/deploy_check")return send(c,chatId,`🩺 Health check:\n- local version: ${VERSION}\n- local runtime: PASS ✅\n- capability registry: active v2\n- multi-file safe actions: guarded ✅\n- forbidden token guard: active v1.1\n- patch planner: active v1.1\n- cost guard: active v1\n- project_map: dynamic v2\n- cleanup_scan: dynamic v2\n- cleanup_plan: read-only v1.1 compact\n- cleanup_manifest: read-only v1.1 paged\n- cleanup_manifest_save: KV snapshot v1\n- cleanup_delete_preview: read-only v1\n- live_pending_v2: read-only ✅\n- rich templates: whitelist v1\n- think/dialog: ${c.openrouter?"active ✅":"no key ⛔"}\n- markers: ${SELF_APPLY_MARKERS.length}`);
