  if(command==="/proposals"){const props=await arr(env,"proposals");return send(c,chatId,props.length?"📦 Proposals:\n"+props.slice(-12).map(p=>`- ${p.id} [${p.state}] ${p.title||p.request}`).join("\n"):"Proposals нет.")}
  if(command==="/show"){const p=findProp(await arr(env,"proposals"),args),l=p?.live_runtime_verify,pl=p?.patch_plan;return send(c,chatId,p?`📦 ${p.id}\nstate: ${p.state}\nrequest: ${p.request||"—"}\ntarget: ${p.target_file||p.code_draft?.target||"—"}\ncapability: ${p.capability||p.operation?.type||"—"}\nrisk: ${p.risk||capRisk(p.operation?.type)||"—"}\nblocked_reason: ${p.blocked_reason||"—"}\npatch planner: ${pl?`${pl.ok?"PASS":"BLOCKED"} / ${pl.risk}`:"none"}\nexpected: ${p.expected||"—"}\nmarker: ${p.marker||"—"}\ncommand: ${p.command||p.operation?.cmd||"—"}\ntemplate: ${p.template||p.operation?.template||"—"}\ndata: ${p.data||p.operation?.data||"—"}\napplied: ${p.apply_result?.commit_sha||"no"}\nverified: ${p.verify?.ok?"yes ✅":"no"}\nlive: ${l?`${l.status} / ${l.command||"—"}`:"none"}`:"Не нашёл proposal.")}
